import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int S = sc.nextInt();
            int C = sc.nextInt();
            int K = sc.nextInt();
            int count = 0;
            for (int i = 0; i <= 360; i++) {
                int intersect = 0;
                for (int j = 1; j <= S; j++) {
                    if (Math.sin(j * i * Math.PI / 180) == 0) intersect++;
                }
                for (int j = 1; j <= C; j++) {
                    if (Math.cos(j * i * Math.PI / 180) == 0) intersect++;
                }
                if (intersect >= K) count++;
            }
            System.out.println(count);
        }
    }
}

