const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [S, C, K] = readline().split(' ').map(Number);
    let count = 0;
    for (let j = 0; j <= 360; j++) {
        let intersect = 0;
        for (let k = 1; k <= S; k++) {
            if (Math.sin(k * j * Math.PI / 180) === 0) intersect++;
        }
        for (let k = 1; k <= C; k++) {
            if (Math.cos(k * j * Math.PI / 180) === 0) intersect++;
        }
        if (intersect >= K) count++;
    }
    console.log(count);
}
